    '{"@odata.type":"#microsoft.graph.windows10CustomConfiguration","assignments":[{"id":"0c07a6a7-5f62-4ce4-a49b-f41c9fabfcd9_1d44d608-f25c-448d-b186-90a9b095ab46","target":{"@odata.type":"#microsoft.graph.groupAssignmentTarget","groupId":"group-paw-global-devices","deviceAndAppManagementAssignmentFilterType":"none","deviceAndAppManagementAssignmentFilterId":null},"sourceId":"0c07a6a7-5f62-4ce4-a49b-f41c9fabfcd9","source":"direct","intent":"apply"}],"description":"Manual Configuration settings: 86.1.3,86.1.4, 86.1.5, 86.1.6, 86.1.7\nExcluding: 86.1.1 (covered by PAW already), 86.1.2 (covered by PAW already), 86.1.8 (as it disables Push Notifications)","assignments@odata.context":"https://graph.microsoft.com/beta/$metadata#deviceManagement/deviceConfigurations(''0c07a6a7-5f62-4ce4-a49b-f41c9fabfcd9'')/microsoft.graph.windows10CustomConfiguration/assignments","id":"0c07a6a7-5f62-4ce4-a49b-f41c9fabfcd9","roleScopeTagIds":"{tag-paw-csm}","supportsScopeTags":true,"omaSettings":[{"@odata.type":"#microsoft.graph.omaSettingInteger","description":"86.1.3 (L2) Ensure ''Configure Authenticated Proxy usage for the Connected User Experience and Telemetry service'' is set to ''Enabled: Disable Authenticated Proxy usage''","value":1,"secretReferenceValueId":null,"displayName":"DisableEnterpriseAuthProxy","isEncrypted":false,"omaUri":"./Device/Vendor/MSFT/Policy/Config/System/DisableEnterpriseAuthProxy","isReadOnly":false},{"@odata.type":"#microsoft.graph.omaSettingInteger","description":"86.1.4 (BL) Ensure ''Enumeration policy for external devices incompatible with Kernel DMA Protection'' is set to ''Enabled: Block All''","value":0,"secretReferenceValueId":null,"displayName":"DeviceEnumerationPolicy","isEncrypted":false,"omaUri":"./Device/Vendor/MSFT/Policy/Config/DmaGuard/DeviceEnumerationPolicy","isReadOnly":false},{"@odata.type":"#microsoft.graph.omaSettingInteger","description":"86.1.5 (L1) Ensure ''Prevent non-admin users from installing packaged Windows apps'' is set to ''E