)

# -- Server-only fields to strip before POSTing --------------------------------
$serverFields = @(
    'id', 'createdDateTime', 'lastModifiedDateTime', 'version',
    'assignments', 'assignments@odata.context', 'supportsScopeTags'
)

# -- Helper: check if policy already exists ------------------------------------
function Get-ConfigPolicyId {
    param([string] $DisplayName)
    $escaped  = $DisplayName -replace "'", "''" -replace '&', '%26'
    $response = Invoke-MgGraphRequest -Method GET `
        -Uri ('https://graph.microsoft.com/beta/deviceManagement/deviceConfigurations?$filter=displayName eq ''' + $escaped + '''')
    ($response.value | Select-Object -First 1)?.id
}

# -- Main loop -----------------------------------------------------------------
Write-Host "
Processing $($policyJsons.Count) configuration policies..." -ForegroundColor White
Write-Host "(LocalGroupMemberships is omitted - requires PAWCSM module to resolve OMA XML value.)" -ForegroundColor Yellow

foreach ($rawJson in $policyJsons) {
    $policy = $rawJson | ConvertFrom-Json

    $displayName = $policy.displayName `
        -replace '\{PAWCSMVersion\}', $PAWCSMVersion `
        -replace 'Windows-10-above', 'Windows-11-above'
    Write-Host "
--- $displayName ---" -ForegroundColor Cyan

    # 1. Skip if already exists
    $policyId = Get-ConfigPolicyId -DisplayName $displayName
    if ($policyId) {
        Write-Host "  Already exists (ID: $policyId)" -ForegroundColor Yellow
    }
    else {
        # 2. Build POST body: strip server fields, fix displayName, roleScopeTagIds, fileName placeholders
        $bodyObj = [ordered]@{}
        foreach ($prop in $policy.PSObject.Properties) {
            if ($prop.Name -notin $serverFields) {
                $bodyObj[$prop.Name] = $prop.Value
            }
        }

        $bodyObj['displayName']      = $displayName
        $bodyObj['roleScopeTagIds']  = @($scopeTag.id)

        if ($bodyObj.Contains('omaSettings') -and $bodyObj['omaSettings']) {
            $bodyObj['omaSettings'] = @(foreach ($s in $bodyObj['omaSettings']) {
                $h = [ordered]@{}
                foreach ($p in $s.PSObject.Properties) {
                    $h[$p.Name] = if ($p.Name -eq 'fileName' -and $p.Value) {
                        $p.Value -replace '\{PAWCSMVersion\}', $PAWCSMVersion
                    } else { $p.Value }
                }
                $h
            })
        }

        $created  = Invoke-MgGraphRequest -Method POST -ContentType 'application/json' `
            -Uri 'https://graph.microsoft.com/beta/deviceManagement/deviceConfigurations' `
            -Body ($bodyObj | ConvertTo-Json -Depth 20)
        $policyId = $created.id
        Write-Host "  Created (ID: $policyId)" -ForegroundColor Green
    }

    # 3. Assign to group
    $assignBody = @{
        assignments = @(@{
            target = @{
                '@odata.type'                              = '#microsoft.graph.groupAssignmentTarget'
                groupId                                    = $entraGroup.id
                deviceAndAppManagementAssignmentFilterType = 'none'
                deviceAndAppManagementAssignmentFilterId   = $null
            }
        })
    } | ConvertTo-Json -Depth 5

    Invoke-MgGraphRequest -Method POST -ContentType 'application/json' `
        -Uri "https://graph.microsoft.com/beta/deviceManagement/deviceConfigurations/$policyId/assign" `
        -Body $assignBody | Out-Null
    Write-Host "  Assigned to '$GroupDisplayName'." -ForegroundColor Green
}

# -- Local Group Memberships policy (requires live SID lookup) -----------------
Write-Host "`n--- PAW-Global-$PAWCSMVersion-Windows-11-above-Local-Group-Memberships-CSP ---" -ForegroundColor Cyan

$lgmDisplayName = "PAW-Global-$PAWCSMVersion-Windows-11-above-Local-Group-Memberships-CSP"
$lgmPolicyId    = Get-ConfigPolicyId -DisplayName $lgmDisplayName

if ($lgmPolicyId) {
    Write-Host "  Already exists (ID: $lgmPolicyId)" -ForegroundColor Yellow
} else {
    Write-Host "  Resolving group SID for '$AllowLogonGroupName'..." -ForegroundColor DarkGray

    $escapedAllow  = $AllowLogonGroupName -replace "'", "''"
    $allowResp     = Invoke-MgGraphRequest -Method GET `
        -Uri ('https://graph.microsoft.com/v1.0/groups?$filter=displayName eq ''' + $escapedAllow + '''&$select=id,displayName,securityIdentifier')
    $allowLogonSid = ($allowResp.value | Select-Object -First 1)?.securityIdentifier

    if (-not $allowLogonSid) { Write-Warning "  Group '$AllowLogonGroupName' not found — Remote Desktop Users SID omitted." }

    $sb = [System.Text.StringBuilder]::new()
    [void]$sb.Append('<GroupConfiguration>')
    [void]$sb.Append('<accessgroup desc="Administrators">')
    [void]$sb.Append('<group action="R" />')
    [void]$sb.Append('<add member="Administrator" />')
    [void]$sb.Append('</accessgroup>')
    [void]$sb.Append('<accessgroup desc="Guests">')
    [void]$sb.Append('<group action="R" />')
    [void]$sb.Append('<add member="Guest" />')
    [void]$sb.Append('</accessgroup>')
    [void]$sb.Append('<accessgroup desc="Remote Desktop Users">')
    [void]$sb.Append('<group action="R" />')
    if ($allowLogonSid) { [void]$sb.Append("<add member=""$allowLogonSid"" />") }
    [void]$sb.Append('</accessgroup>')
    [void]$sb.Append('</GroupConfiguration>')
    $omaXml = $sb.ToString()

    $lgmBody = [ordered]@{
        '@odata.type'                               = '#microsoft.graph.windows10CustomConfiguration'
        description                                 = 'Updates the local group memberships'
        displayName                                 = $lgmDisplayName
        roleScopeTagIds                             = @($scopeTag.id)
        deviceManagementApplicabilityRuleOsEdition  = $null
        deviceManagementApplicabilityRuleOsVersion  = $null
        deviceManagementApplicabilityRuleDeviceMode = $null
        omaSettings                                 = @(
            [ordered]@{
                '@odata.type' = '#microsoft.graph.omaSettingString'
                displayName   = 'LocalUsersAndGroups - Local User Group Configuration'
                description   = $null
                omaUri        = './Device/Vendor/MSFT/Policy/Config/LocalUsersAndGroups/Configure'
                isEncrypted   = $false
                value         = $omaXml
            }
        )
    }

    $created     = Invoke-MgGraphRequest -Method POST -ContentType 'application/json' `
        -Uri 'https://graph.microsoft.com/beta/deviceManagement/deviceConfigurations' `
        -Body ($lgmBody | ConvertTo-Json -Depth 10)
    $lgmPolicyId = $created.id
    Write-Host "  Created (ID: $lgmPolicyId)" -ForegroundColor Green
}

$lgmAssignBody = @{
    assignments = @(@{
        target = @{
            '@odata.type'                              = '#microsoft.graph.groupAssignmentTarget'
            groupId                                    = $entraGroup.id
            deviceAndAppManagementAssignmentFilterType = 'none'
            deviceAndAppManagementAssignmentFilterId   = $null
        }
    })
} | ConvertTo-Json -Depth 5

Invoke-MgGraphRequest -Method POST -ContentType 'application/json' `
    -Uri "https://graph.microsoft.com/beta/deviceManagement/deviceConfigurations/$lgmPolicyId/assign" `
    -Body $lgmAssignBody | Out-Null
Write-Host "  Assigned to '$GroupDisplayName'." -ForegroundColor Green

Write-Host "`nDone." -ForegroundColor Cyan
